// ======================== HELPER: parse kit short name ========================

export function parseKitShortName(fullName: string): string {
  const parenIdx = fullName.indexOf('(');
  const periodIdx = fullName.indexOf('. ', 10);
  const cutIdx = parenIdx > 0 && periodIdx > 0 ? Math.min(parenIdx, periodIdx) : (parenIdx > 0 ? parenIdx : periodIdx);
  if (cutIdx > 0) {
    return fullName.substring(0, cutIdx).trim();
  }
  return fullName;
}

